{"path":"notes_app/storage.py","content":"import json

class NotesStorage:
    def __init__(self, filepath='notes.json'):
        self.filepath = filepath
        self.notes = []
        self.load()

    def load(self):
        try:
            with open(self.filepath, 'r') as file:
                self.notes = json.load(file)
        except FileNotFoundError:
            self.notes = []

    def save(self):
        with open(self.filepath, 'w') as file:
            json.dump(self.notes, file, indent=4)

    def add(self, note):
        if not note.strip():
            raise ValueError('Note cannot be empty')
        self.notes.append(note)
        self.save()

    def list(self):
        return self.notes

    def search(self, query):
        return [note for note in self.notes if query.lower() in note.lower()]

    def delete(self, index):
        if 0 <= index < len(self.notes):
            del self.notes[index]
            self.save()
        else:
            raise IndexError('Note index out of range')"}

{"path":"notes_app/cli.py","content":"import click
from .storage import NotesStorage

click.disable_unicode_literals = True

class NotesCLI:
    def __init__(self, storage):
        self.storage = storage

    @click.group()
    def cli():
        pass

    @cli.command()
    @click.argument('note', nargs=-1)
    def add(note):
        note_text = ' '.join(note)
        try:
            storage.add(note_text)
            click.echo(f'Note added: {note_text}')
        except ValueError as e:
            click.echo(e, err=True)

    @cli.command()
    def list():
        notes = storage.list()
        if not notes:
            click.echo('No notes found.')
        else:
            for i, note in enumerate(notes):
                click.echo(f'{i}: {note}')

    @cli.command()
    @click.argument('query')
    def search(query):
        results = storage.search(query)
        if not results:
            click.echo(f'No notes found for query: {query}')
        else:
            for i, note in enumerate(results):
                click.echo(f'{i}: {note}')

    @cli.command()
    @click.argument('index', type=int)
    def delete(index):
        try:
            storage.delete(index)
            click.echo(f'Note at index {index} deleted.')
        except (IndexError, ValueError) as e:
            click.echo(e, err=True)

if __name__ == '__main__':
    storage = NotesStorage()
    cli()"}

